function Stacker() {
  // Internal state
  this.dir = 0; // 0=up,1=right,2=down,3=left
  this.inv = 0; // carried blocks
  this.targetInv = 20; // aim to carry this many blocks
  this.seenGold = false;
  this.steps = 0;

  function isWall(c) { return c && c.type === 1; }
  function isGold(c) { return c && c.type === 3; }
  function isBlock(c) { return c && c.type === 2; }
  function canStep(curr, n) { return n && !isWall(n) && Math.abs(n.level - curr.level) <= 1; }
  function needRaise(curr, n) { return n && (n.level - curr.level) > 1; }
