  function leftOf(d) { return (d + 3) & 3; }
  function backOf(d) { return (d + 2) & 3; }

  function getNeighbor(cell, d) {
    return d === 0 ? cell.up : d === 1 ? cell.right : d === 2 ? cell.down : cell.left;
  }

  function chooseExploreDir(cell) {
    // Right-hand wall-following priority: right, straight, left, back
    var d = this.dir;
    var prio = [rightOf(d), d, leftOf(d), backOf(d)];
    for (var i = 0; i < prio.length; i++) {
      var nd = prio[i];
      var n = getNeighbor(cell, nd);
      if (!n || isWall(n)) continue;
      if (canStep(cell, n)) return nd;
