      // No action strictly needed; pick/drop could be no-ops. Return any move.
      return "left";
    }

    // Detect if gold visible
    var nbrs = [cell.up, cell.right, cell.down, cell.left];
    var goldDirs = [];
    for (var i = 0; i < 4; i++) {
      if (isGold(nbrs[i])) goldDirs.push(i);
    }
    if (goldDirs.length > 0) this.seenGold = true; else this.seenGold = false;

    // Priority 1: If gold visible, approach it
    if (goldDirs.length > 0) {
      // Pick one (prefer the one with minimal elevation difference)
      var bestD = goldDirs[0];
      var bestDiff = Math.abs(nbrs[bestD].level - cell.level);
      for (var gi = 1; gi < goldDirs.length; gi++) {
        var d = goldDirs[gi];
        var diff = Math.abs(nbrs[d].level - cell.level);
        if (diff < bestDiff) { bestDiff = diff; bestD = d; }
      }
      var target = getNeighbor(cell, bestD);
      // Adjust elevation if needed
      if (needRaise(cell, target)) {
        if (this.inv > 0) {
          return "drop";
        } else {
          // No inventory: try to move toward a block neighbor to collect
          for (var i2 = 0; i2 < 4; i2++) {
            var n2 = nbrs[i2];
            if (n2 && isBlock(n2) && canStep(cell, n2)) {
              this.dir = i2;
              return dirToStr(i2);
            }
          }
          // Otherwise, explore normally
        }
      } else if (needLower(cell, target)) {
        // Too steep down; if standing on blocks, pick to lower
        if (isBlock(cell) && cell.level > 0) {
          this.inv++;
          return "pickup";
        } else {
          // Find alternative approach or explore
        }
      } else if (canStep(cell, target)) {
        this.dir = bestD;
        return dirToStr(bestD);
      } else {
        // Not directly step-able and can't adjust; fall back to exploration
      }
    }

    // Priority 2: Resource gathering on block cells, but avoid harming a needed upward move
    var anyUpStep = false;
    for (var i3 = 0; i3 < 4; i3++) {
      var n3 = nbrs[i3];
      if (n3 && !isWall(n3) && (n3.level === cell.level + 1)) anyUpStep = true;
    }
    if (isBlock(cell) && cell.level > 0 && this.inv < this.targetInv && !anyUpStep) {
      this.inv++;
      return "pickup";
    }

    // Priority 3: Exploration using right-hand rule
    var moveDir = chooseExploreDir.call(this, cell);
    if (moveDir !== null) {
      var target2 = getNeighbor(cell, moveDir);
      // If need to raise to move, drop (if we have inventory)
      if (needRaise(cell, target2)) {
        if (this.inv > 0) {
          return "drop";
        } else {
          // Try to move to a nearby block to collect
          for (var j = 0; j < 4; j++) {
            var nb = nbrs[j];
            if (nb && isBlock(nb) && canStep(cell, nb)) {
              this.dir = j;
              return dirToStr(j);
            }
          }
          // If on a block, pick to gather (only if not about to go up)
          if (isBlock(cell) && cell.level > 0) {
            this.inv++;
            return "pickup";
          }
          // Otherwise, try a different direction that doesn't require raising
          for (var k = 0; k < 4; k++) {
            var alt = getNeighbor(cell, k);
            if (alt && !isWall(alt) && canStep(cell, alt)) { this.dir = k; return dirToStr(k); }
