          // If still stuck, no-op movement
        }
      } else if (needLower(cell, target2)) {
        // Need to go down steeply; if standing on blocks, pick to lower
        if (isBlock(cell) && cell.level > 0) {
          this.inv++;
          return "pickup";
        } else {
          // Choose a different direction that doesn't require lowering
          for (var k2 = 0; k2 < 4; k2++) {
